namespace BlazorApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.Add(new Notification(_nextId++, "Welcome to the notification center!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new Notification(_nextId++, "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new Notification(_nextId++, "New feature: dark mode is now available.", DateTime.UtcNow.AddMinutes(-2)));
    }

    /// <summary>
    /// Gets all notifications up to this point.
    /// </summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>
    /// Gets notifications added after the given ID.
    /// </summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            var newer = _notifications.Where(n => n.Id > lastSeenId).ToList();
            return Task.FromResult(newer);
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called internally; in a real app this would come from an external source.
    /// </summary>
    public void SimulateIncoming()
    {
        lock (_lock)
        {
            // ~30% chance of a new notification each poll
            if (Random.Shared.Next(100) < 30)
            {
                var messages = new[]
                {
                    "You have a new follower!",
                    "Your build completed successfully.",
                    "Someone commented on your post.",
                    "Reminder: team standup in 15 minutes.",
                    "Deployment to production succeeded.",
                    "New pull request assigned to you."
                };
                var msg = messages[Random.Shared.Next(messages.Length)];
                _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
            }
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<Notification>? PersistedNotifications { get; set; }

    private List<Notification> notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override async Task OnInitializedAsync()
    {
        if (PersistedNotifications is not null)
        {
            // Restored from prerender — no need to fetch again
            notifications = PersistedNotifications;
        }
        else
        {
            notifications = await NotificationService.GetNotificationsAsync();
            PersistedNotifications = notifications;
        }

        _lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Only starts after the page is truly interactive (not during prerender)
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(5000, ct);

                // Simulate external notifications arriving
                NotificationService.SimulateIncoming();

                var newer = await NotificationService.GetNotificationsSinceAsync(_lastSeenId);
                if (newer.Count > 0)
                {
                    notifications.AddRange(newer);
                    _lastSeenId = newer.Max(n => n.Id);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

